const body = $json.body || $json;
const type = body.type;
const payload = body.payload || {};
const user = body.user || {};

const firstName = (user.first_name || '').trim().split(/\s+/).filter(Boolean)[0] || '';
const firstLastName = (user.last_name || '').trim().split(/\s+/).filter(Boolean)[0] || '';
const greetingName = [firstName, firstLastName].filter(Boolean).join(' ') || 'usuario';

if (type === 'EMAIL_VERIFICATION') {
  const verificationUrl = payload.verification_url || '';
  const verificationApiUrl = payload.verification_api_url || '';
  const token = payload.token || '';

  return [
    {
      json: {
        to: payload.email || '',
        subject: 'Confirma tu cuenta en Narino Cultura',
        html: [
          '<div style="font-family: Arial, sans-serif; max-width: 640px; margin: 0 auto; color: #1f2937; line-height: 1.6;">',
          '<h2 style="color: #7c2d12; margin-bottom: 16px;">Bienvenido a Narino Cultura</h2>',
          '<p>Hola ' + greetingName + ', gracias por registrarte.</p>',
          '<p>Para activar tu cuenta, haz clic en el siguiente boton:</p>',
          '<p style="margin: 24px 0;">',
          '<a href="' + verificationUrl + '" style="display:inline-block;padding:12px 20px;background:#7c2d12;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;">Verificar correo</a>',
          '</p>',
          '<p>Si el boton no funciona, copia y pega este enlace completo en tu navegador:</p>',
          '<p style="word-break: break-word;"><a href="' + verificationUrl + '">' + verificationUrl + '</a></p>',
          token ? '<p>Tambien puedes verificar manualmente enviando este token desde la aplicacion o Postman:</p>' : '',
          token ? '<p><strong>' + token + '</strong></p>' : '',
          verificationApiUrl ? '<p>Endpoint de verificacion manual: <strong>' + verificationApiUrl + '</strong></p>' : '',
          '<p style="margin-top: 24px; color: #6b7280; font-size: 14px;">Si no creaste esta cuenta, puedes ignorar este mensaje.</p>',
          '</div>'
        ].filter(Boolean).join('')
      }
    }
  ];
}

if (type === 'PASSWORD_RESET') {
  const resetUrl = payload.reset_url || '';
  const token = payload.token || '';

  return [
    {
      json: {
        to: payload.email || '',
        subject: 'Restablece tu contrasena en Narino Cultura',
        html: [
          '<div style="font-family: Arial, sans-serif; max-width: 640px; margin: 0 auto; color: #1f2937; line-height: 1.6;">',
          '<h2 style="color: #7c2d12; margin-bottom: 16px;">Recuperacion de contrasena</h2>',
          '<p>Hola ' + greetingName + ', recibimos una solicitud para cambiar tu contrasena.</p>',
          '<p>Puedes continuar desde este enlace:</p>',
          '<p style="margin: 24px 0;">',
          '<a href="' + resetUrl + '" style="display:inline-block;padding:12px 20px;background:#7c2d12;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;">Restablecer contrasena</a>',
          '</p>',
          '<p>Si el boton no funciona, copia y pega este enlace completo en tu navegador:</p>',
          '<p style="word-break: break-word;"><a href="' + resetUrl + '">' + resetUrl + '</a></p>',
          token ? '<p>Token de respaldo: <strong>' + token + '</strong></p>' : '',
          '<p style="margin-top: 24px; color: #6b7280; font-size: 14px;">Si no solicitaste este cambio, ignora este mensaje.</p>',
          '</div>'
        ].filter(Boolean).join('')
      }
    }
  ];
}

return [
  {
    json: {
      to: payload.email || '',
      subject: 'Evento no manejado: ' + (type || 'SIN_TIPO'),
      html: '<pre>' + JSON.stringify(body, null, 2) + '</pre>'
    }
  }
];
